#!/usr/bin/env python3
import os, sys, ast

REPO = os.path.dirname(os.path.abspath(__file__))

def read(f):
    with open(os.path.join(REPO, f), "r", encoding="utf-8") as fh:
        return fh.read()

def write(f, content):
    with open(os.path.join(REPO, f), "w", encoding="utf-8") as fh:
        fh.write(content)

EXPANSIONS = {
"pm-kisan": {
 "intro": "\u092a\u094d\u0930\u0927\u093e\u0928\u092e\u0902\u0924\u094d\u0930\u0940 \u0915\u093f\u0938\u093e\u0928 \u0938\u092e\u094d\u092e\u093e\u0928 \u0928\u093f\u0927\u093f (PM-KISAN) \u092d\u093e\u0930\u0924 \u0938\u0930\u0915\u093e\u0930 \u0915\u0940 \u092a\u094d\u0930\u092e\u0941\u0916 \u092f\u094b\u091c\u0928\u093e \u0939\u0948 \u091c\u093f\u0938\u092e\u0947\u0902 \u092a\u093e\u0924\u094d\u0930 \u0915\u093f\u0938\u093e\u0928 \u092a\u0930\u093f\u0935\u093e\u0930\u094b\u0902 \u0915\u094b \u0939\u0930 \u0938\u093e\u0932 \u20b96,000 \u0915\u0940 \u0906\u092f \u0938\u0939\u093e\u092f\u0924\u093e \u0924\u0940\u0928 \u0915\u093f\u0938\u094d\u0924\u094b\u0902 (\u20b92,000 \u092a\u094d\u0930\u0924\u094d\u092f\u0947\u0915) \u092e\u0947\u0902 \u0938\u0940\u0927\u0947 \u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u0947 \u092e\u0947\u0902 DBT \u0915\u0947 \u092e\u093e\u0927\u094d\u092f\u092e \u0938\u0947 \u0926\u0940 \u091c\u093e\u0924\u0940 \u0939\u0948\u0964 \u092f\u0939 \u092f\u094b\u091c\u0928\u093e \u092b\u093c\u0930\u0935\u0930\u0940 2019 \u092e\u0947\u0902 \u0915\u0943\u0937\u093f \u090f\u0935\u0902 \u0915\u093f\u0938\u093e\u0928 \u0915\u0932\u094d\u092f\u093e\u0923 \u092e\u0902\u0924\u094d\u0930\u093e\u0932\u092f \u0926\u094d\u0935\u093e\u0930\u093e \u0936\u0941\u0930\u0942 \u0915\u0940 \u0917\u0908 \u0925\u0940\u0964 \u0905\u092c \u0924\u0915 11 \u0915\u0930\u094b\u0921\u093c \u0938\u0947 \u0905\u0927\u093f\u0915 \u0915\u093f\u0938\u093e\u0928 \u092a\u0930\u093f\u0935\u093e\u0930 \u0907\u0938 \u092f\u094b\u091c\u0928\u093e \u0915\u093e \u0932\u093e\u092d \u0909\u0920\u093e \u091a\u0941\u0915\u0947 \u0939\u0948\u0902\u0964 \u0906\u0935\u0947\u0926\u0928 pmkisan.gov.in \u092a\u0930 \u0928\u093f\u0903\u0936\u0941\u0932\u094d\u0915 \u0915\u093f\u092f\u093e \u091c\u093e \u0938\u0915\u0924\u093e \u0939\u0948\u0964 \u0939\u0947\u0932\u094d\u092a\u0932\u093e\u0907\u0928: 155261 / 011-24300606\u0964",
 "benefits": ["\u20b96,000 \u092a\u094d\u0930\u0924\u093f \u0935\u0930\u094d\u0937 \u2014 \u20b92,000 \u0915\u0940 \u0924\u0940\u0928 \u0938\u092e\u093e\u0928 \u0915\u093f\u0938\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 (\u0905\u092a\u094d\u0930\u0948\u0932-\u091c\u0941\u0932\u093e\u0908, \u0905\u0917\u0938\u094d\u0924-\u0928\u0935\u0902\u092c\u0930, \u0926\u093f\u0938\u0902\u092c\u0930-\u092e\u093e\u0930\u094d\u091a)", "\u092a\u0948\u0938\u093e \u0938\u0940\u0927\u0947 \u0906\u0927\u093e\u0930-\u0932\u093f\u0902\u0915\u094d\u0921 \u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u0947 \u092e\u0947\u0902 DBT \u0938\u0947 \u2014 \u0915\u094b\u0908 \u092c\u093f\u091a\u094c\u0932\u093f\u092f\u093e \u0928\u0939\u0940\u0902", "100% \u0915\u0947\u0902\u0926\u094d\u0930 \u0938\u0930\u0915\u093e\u0930 \u0926\u094d\u0935\u093e\u0930\u093e \u0935\u093f\u0924\u094d\u0924\u092a\u094b\u0937\u093f\u0924 \u2014 \u0930\u093e\u091c\u094d\u092f \u0915\u093e \u0915\u094b\u0908 \u0939\u093f\u0938\u094d\u0938\u093e \u0928\u0939\u0940\u0902", "\u0915\u094b\u0908 \u0906\u0935\u0947\u0926\u0928 \u0936\u0941\u0932\u094d\u0915 \u0928\u0939\u0940\u0902 \u2014 \u0930\u091c\u093f\u0938\u094d\u091f\u094d\u0930\u0947\u0936\u0928 \u092a\u0942\u0930\u0940 \u0924\u0930\u0939 \u0928\u093f\u0903\u0936\u0941\u0932\u094d\u0915", "\u0915\u094b\u0908 \u091c\u093c\u092e\u0940\u0928 \u0938\u0940\u092e\u093e \u0928\u0939\u0940\u0902 \u2014 \u091b\u094b\u091f\u0947 \u0914\u0930 \u0938\u0940\u092e\u093e\u0902\u0924 \u0915\u093f\u0938\u093e\u0928 \u092d\u0940 \u092a\u093e\u0924\u094d\u0930 (2019 \u092e\u0947\u0902 \u0938\u0940\u092e\u093e \u0939\u091f\u093e\u0908 \u0917\u0908)"],
 "eligibility": ["\u092d\u093e\u0930\u0924 \u0915\u093e \u0915\u094b\u0908 \u092d\u0940 \u092d\u0942\u092e\u093f\u0927\u093e\u0930\u0915 \u0915\u093f\u0938\u093e\u0928 \u092a\u0930\u093f\u0935\u093e\u0930 (\u092a\u0924\u093f, \u092a\u0924\u094d\u0928\u0940, \u0928\u093e\u092c\u093e\u0932\u093f\u0917 \u092c\u091a\u094d\u091a\u0947)", "\u091b\u094b\u091f\u0947 \u0914\u0930 \u0938\u0940\u092e\u093e\u0902\u0924 \u0915\u093f\u0938\u093e\u0928 \u2014 \u0938\u092d\u0940 \u092d\u0942\u092e\u093f\u0927\u093e\u0930\u0915 \u092a\u093e\u0924\u094d\u0930", "\u274c \u0938\u0902\u0938\u094d\u0925\u093e\u0917\u0924 \u092d\u0942\u092e\u093f\u0927\u093e\u0930\u0915 (\u091f\u094d\u0930\u0938\u094d\u091f, \u0915\u0902\u092a\u0928\u0940, \u0938\u094b\u0938\u093e\u092f\u091f\u0940) \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902", "\u274c \u0906\u092f\u0915\u0930 \u0926\u093e\u0924\u093e (\u092a\u093f\u091b\u0932\u0947 Assessment Year \u092e\u0947\u0902) \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902", "\u274c \u0935\u0930\u094d\u0924\u092e\u093e\u0928/\u092a\u0942\u0930\u094d\u0935 \u0938\u093e\u0902\u0938\u0926, \u0935\u093f\u0927\u093e\u092f\u0915, \u092e\u0902\u0924\u094d\u0930\u0940, \u092e\u0939\u093e\u092a\u094c\u0930 \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902", "\u274c \u20b910,000+ \u092e\u093e\u0938\u093f\u0915 \u092a\u0947\u0902\u0936\u0928 \u0935\u093e\u0932\u0947 \u0938\u0930\u0915\u093e\u0930\u0940 \u0938\u0947\u0935\u093e\u0928\u093f\u0935\u0943\u0924\u094d\u0924 \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902 (MTS \u091b\u094b\u0921\u093c\u0915\u0930)", "\u274c \u092a\u094d\u0930\u0948\u0915\u094d\u091f\u093f\u0938 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0947 \u0921\u0949\u0915\u094d\u091f\u0930, \u0907\u0902\u091c\u0940\u0928\u093f\u092f\u0930, \u0935\u0915\u0940\u0932, CA \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902"],
 "documents": ["\u0906\u0927\u093e\u0930 \u0915\u093e\u0930\u094d\u0921 \u2014 \u0905\u0928\u093f\u0935\u093e\u0930\u094d\u092f (\u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u0947 \u0938\u0947 \u0932\u093f\u0902\u0915 \u0939\u094b\u0928\u093e \u091a\u093e\u0939\u093f\u090f)", "\u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u093e \u2014 \u092a\u093e\u0938\u092c\u0941\u0915 \u092f\u093e \u0915\u0948\u0902\u0938\u0932\u094d\u0921 \u091a\u0947\u0915 (\u0906\u0927\u093e\u0930-\u0932\u093f\u0902\u0915\u094d\u0921)", "\u092d\u0942\u092e\u093f \u0915\u0947 \u0926\u0938\u094d\u0924\u093e\u0935\u0947\u091c\u093c \u2014 \u0916\u0924\u094c\u0928\u0940 / \u0916\u0938\u0930\u093e / \u092d\u0942\u092e\u093f \u092a\u091f\u094d\u091f\u093e / \u0930\u091c\u093f\u0938\u094d\u091f\u094d\u0930\u0940", "\u092e\u094b\u092c\u093e\u0907\u0932 \u0928\u0902\u092c\u0930 \u2014 \u0906\u0927\u093e\u0930 \u0938\u0947 \u0930\u091c\u093f\u0938\u094d\u091f\u0930\u094d\u0921 (OTP \u0935\u0947\u0930\u093f\u092b\u093c\u093f\u0915\u0947\u0936\u0928 \u0915\u0947 \u0932\u093f\u090f)"],
 "howToApply": ["pmkisan.gov.in \u092a\u0930 \u091c\u093e\u090f\u0902", "'New Farmer Registration' \u092a\u0930 \u0915\u094d\u0932\u093f\u0915 \u0915\u0930\u0947\u0902", "Rural (\u0917\u094d\u0930\u093e\u092e\u0940\u0923) \u092f\u093e Urban (\u0936\u0939\u0930\u0940) \u0915\u093f\u0938\u093e\u0928 \u091a\u0941\u0928\u0947\u0902", "\u0906\u0927\u093e\u0930 \u0928\u0902\u092c\u0930, \u092e\u094b\u092c\u093e\u0907\u0932 \u0928\u0902\u092c\u0930, \u0914\u0930 \u0930\u093e\u091c\u094d\u092f \u0926\u0930\u094d\u091c \u0915\u0930\u0947\u0902", "\u0906\u0927\u093e\u0930 \u092a\u0930 \u0930\u091c\u093f\u0938\u094d\u091f\u0930\u094d\u0921 \u092e\u094b\u092c\u093e\u0907\u0932 \u092a\u0930 OTP \u0906\u090f\u0917\u093e \u2014 \u0935\u0947\u0930\u093f\u092b\u093c\u093e\u0908 \u0915\u0930\u0947\u0902", "\u0935\u094d\u092f\u0915\u094d\u0924\u093f\u0917\u0924 \u0935\u093f\u0935\u0930\u0923, \u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u093e, \u0914\u0930 \u092d\u0942\u092e\u093f \u0935\u093f\u0935\u0930\u0923 \u092d\u0930\u0947\u0902", "Submit \u0915\u0930\u0947\u0902 \u0914\u0930 \u0930\u091c\u093f\u0938\u094d\u091f\u094d\u0930\u0947\u0936\u0928 \u0928\u0902\u092c\u0930 \u0928\u094b\u091f \u0915\u0930 \u0932\u0947\u0902", "\u0935\u0948\u0915\u0932\u094d\u092a\u093f\u0915: \u0928\u091c\u093c\u0926\u0940\u0915\u0940 CSC (\u20b915-30 \u0936\u0941\u0932\u094d\u0915) \u092f\u093e \u0932\u0947\u0916\u092a\u093e\u0932/\u092a\u091f\u0935\u093e\u0930\u0940 \u0938\u0947 \u092d\u0940 \u0915\u0930\u093e\u090f\u0902"],
 "faqs": [["PM Kisan \u092e\u0947\u0902 \u0915\u093f\u0924\u0928\u0947 \u092a\u0948\u0938\u0947 \u092e\u093f\u0932\u0924\u0947 \u0939\u0948\u0902?", "\u092a\u093e\u0924\u094d\u0930 \u0915\u093f\u0938\u093e\u0928 \u092a\u0930\u093f\u0935\u093e\u0930\u094b\u0902 \u0915\u094b \u092a\u094d\u0930\u0924\u093f \u0935\u0930\u094d\u0937 \u20b96,000 \u0926\u093f\u090f \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u092f\u0939 \u20b92,000 \u0915\u0940 \u0924\u0940\u0928 \u0915\u093f\u0938\u094d\u0924\u094b\u0902 \u092e\u0947\u0902 \u0939\u0930 4 \u092e\u0939\u0940\u0928\u0947 \u092a\u0930 \u0938\u0940\u0927\u0947 \u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u0947 \u092e\u0947\u0902 DBT \u0915\u0947 \u092e\u093e\u0927\u094d\u092f\u092e \u0938\u0947 \u092d\u0947\u091c\u0947 \u091c\u093e\u0924\u0947 \u0939\u0948\u0902\u0964 \u0915\u093f\u0938\u094d\u0924\u0947\u0902 \u0905\u092a\u094d\u0930\u0948\u0932-\u091c\u0941\u0932\u093e\u0908, \u0905\u0917\u0938\u094d\u0924-\u0928\u0935\u0902\u092c\u0930, \u0914\u0930 \u0926\u093f\u0938\u0902\u092c\u0930-\u092e\u093e\u0930\u094d\u091a \u092e\u0947\u0902 \u0906\u0924\u0940 \u0939\u0948\u0902\u0964"], ["\u0915\u093f\u0938\u094d\u0924 \u0915\u094d\u092f\u094b\u0902 \u0928\u0939\u0940\u0902 \u0906 \u0930\u0939\u0940?", "\u0915\u093f\u0938\u094d\u0924 \u0928 \u0906\u0928\u0947 \u0915\u0947 \u0915\u093e\u0930\u0923: e-KYC \u092a\u0942\u0930\u093e \u0928\u0939\u0940\u0902 \u0939\u094b\u0928\u093e, \u092c\u0948\u0902\u0915 \u0916\u093e\u0924\u093e \u0906\u0927\u093e\u0930 \u0938\u0947 \u0932\u093f\u0902\u0915 \u0928 \u0939\u094b\u0928\u093e, \u092d\u0942\u092e\u093f \u0930\u093f\u0915\u0949\u0930\u094d\u0921 \u092e\u0947\u0902 \u0924\u094d\u0930\u0941\u091f\u093f, \u092f\u093e \u0906\u0935\u0947\u0926\u0928 \u092e\u0947\u0902 \u0917\u0932\u0924 \u091c\u093e\u0928\u0915\u093e\u0930\u0940\u0964 pmkisan.gov.in \u092a\u0930 Beneficiary Status \u091a\u0947\u0915 \u0915\u0930\u0947\u0902 \u092f\u093e \u0928\u091c\u093c\u0926\u0940\u0915\u0940 CSC/\u0915\u0943\u0937\u093f \u0915\u093e\u0930\u094d\u092f\u093e\u0932\u092f \u0938\u0947 \u0938\u0902\u092a\u0930\u094d\u0915 \u0915\u0930\u0947\u0902\u0964"], ["e-KYC \u0915\u0948\u0938\u0947 \u0915\u0930\u0947\u0902?", "\u0926\u094b \u0924\u0930\u0940\u0915\u0947: (1) OTP-based \u2014 pmkisan.gov.in \u092a\u0930 \u0906\u0927\u093e\u0930 \u0928\u0902\u092c\u0930 \u0921\u093e\u0932\u0947\u0902, \u092e\u094b\u092c\u093e\u0907\u0932 OTP \u0935\u0947\u0930\u093f\u092b\u093c\u093e\u0908 \u0915\u0930\u0947\u0902; (2) Biometric \u2014 \u0928\u091c\u093c\u0926\u0940\u0915\u0940 CSC \u092a\u0930 \u092b\u093c\u093f\u0902\u0917\u0930\u092a\u094d\u0930\u093f\u0902\u091f/\u0906\u0907\u0930\u093f\u0938 \u0938\u094d\u0915\u0948\u0928 \u0915\u0930\u093e\u090f\u0902\u0964 e-KYC \u0905\u0928\u093f\u0935\u093e\u0930\u094d\u092f \u0939\u0948 \u2014 \u092c\u093f\u0928\u093e \u0907\u0938\u0915\u0947 \u0915\u093f\u0938\u094d\u0924 \u0928\u0939\u0940\u0902 \u0906\u090f\u0917\u0940\u0964"], ["\u0911\u0928\u0932\u093e\u0907\u0928 \u0930\u091c\u093f\u0938\u094d\u091f\u094d\u0930\u0947\u0936\u0928 \u0915\u0948\u0938\u0947 \u0915\u0930\u0947\u0902?", "pmkisan.gov.in \u2192 New Farmer Registration \u2192 Rural/Urban \u091a\u0941\u0928\u0947\u0902 \u2192 \u0906\u0927\u093e\u0930, \u092e\u094b\u092c\u093e\u0907\u0932, \u0930\u093e\u091c\u094d\u092f \u0921\u093e\u0932\u0947\u0902 \u2192 OTP \u0935\u0947\u0930\u093f\u092b\u093c\u093e\u0908 \u2192 \u092c\u0948\u0902\u0915 \u0935 \u091c\u093c\u092e\u0940\u0928 \u0935\u093f\u0935\u0930\u0923 \u092d\u0930\u0947\u0902 \u2192 \u0938\u092c\u092e\u093f\u091f\u0964 CSC \u092f\u093e \u0932\u0947\u0916\u092a\u093e\u0932/\u092a\u091f\u0935\u093e\u0930\u0940 \u0938\u0947 \u092d\u0940 \u0915\u0930\u093e\u092f\u093e \u091c\u093e \u0938\u0915\u0924\u093e \u0939\u0948\u0964"], ["\u0915\u094c\u0928 \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948?", "\u0938\u0902\u0938\u094d\u0925\u093e\u0917\u0924 \u092d\u0942\u092e\u093f\u0927\u093e\u0930\u0915, \u0906\u092f\u0915\u0930 \u0926\u093e\u0924\u093e, \u0935\u0930\u094d\u0924\u092e\u093e\u0928/\u092a\u0942\u0930\u094d\u0935 \u0938\u093e\u0902\u0938\u0926-\u0935\u093f\u0927\u093e\u092f\u0915-\u092e\u0902\u0924\u094d\u0930\u0940, \u20b910,000+ \u092e\u093e\u0938\u093f\u0915 \u092a\u0947\u0902\u0936\u0928 \u0935\u093e\u0932\u0947 \u0938\u0947\u0935\u093e\u0928\u093f\u0935\u0943\u0924\u094d\u0924 (MTS \u091b\u094b\u0921\u093c\u0915\u0930), \u0914\u0930 \u092a\u094d\u0930\u0948\u0915\u094d\u091f\u093f\u0938 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u0947 \u0921\u0949\u0915\u094d\u091f\u0930, \u0907\u0902\u091c\u0940\u0928\u093f\u092f\u0930, \u0935\u0915\u0940\u0932, CA \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902\u0964"], ["Beneficiary List \u092e\u0947\u0902 \u0928\u093e\u092e \u0915\u0948\u0938\u0947 \u0926\u0947\u0916\u0947\u0902?", "pmkisan.gov.in \u2192 Beneficiary List \u2192 \u0930\u093e\u091c\u094d\u092f, \u091c\u093c\u093f\u0932\u093e, \u0924\u0939\u0938\u0940\u0932, \u092c\u094d\u0932\u0949\u0915, \u0917\u093e\u0901\u0935 \u091a\u0941\u0928\u0947\u0902 \u2192 Get Report \u2192 \u0905\u092a\u0928\u0947 \u0917\u093e\u0901\u0935 \u0915\u0940 \u0938\u0942\u091a\u0940 \u092e\u0947\u0902 \u0928\u093e\u092e \u0916\u094b\u091c\u0947\u0902\u0964"], ["\u0915\u094d\u092f\u093e \u0915\u093f\u0930\u093e\u090f \u0915\u0940 \u091c\u093c\u092e\u0940\u0928 \u092a\u0930 \u0916\u0947\u0924\u0940 \u0915\u0930\u0928\u0947 \u0935\u093e\u0932\u093e \u092a\u093e\u0924\u094d\u0930 \u0939\u0948?", "\u0928\u0939\u0940\u0902, PM Kisan \u0915\u0947\u0935\u0932 \u092d\u0942\u092e\u093f\u0927\u093e\u0930\u0915 \u0915\u093f\u0938\u093e\u0928\u094b\u0902 \u0915\u0947 \u0932\u093f\u090f \u0939\u0948\u0964 \u092c\u091f\u093e\u0908\u0926\u093e\u0930 (sharecropper) \u092f\u093e \u0915\u093f\u0930\u093e\u090f\u0926\u093e\u0930 \u0915\u093f\u0938\u093e\u0928 \u092a\u093e\u0924\u094d\u0930 \u0928\u0939\u0940\u0902 \u0939\u0948\u0902\u0964 \u0915\u0941\u091b \u0930\u093e\u091c\u094d\u092f\u094b\u0902 \u0915\u0940 \u0905\u0932\u0917 \u092f\u094b\u091c\u0928\u093e\u090f\u0901 \u0907\u0928\u0915\u0947 \u0932\u093f\u090f \u0909\u092a\u0932\u092c\u094d\u0927 \u0939\u0948\u0902\u0964"]]
}
}

print("\n\u0001f527 Expanding PM Kisan in schemes_data.py ...")
sd = read("schemes_data.py")
count = 0

for slug, new_data in EXPANSIONS.items():
    slug_marker = '"slug": "' + slug + '"'
    alt_marker = '"slug":"' + slug + '"'
    pos = sd.find(slug_marker)
    if pos < 0:
        pos = sd.find(alt_marker)
    if pos < 0:
        print("  Warning: " + slug + " not found")
        continue
    hi_start = sd.find('"hi":', pos)
    if hi_start < 0 or hi_start > pos + 2000:
        hi_start = sd.find('"hi" :', pos)
    if hi_start < 0 or hi_start > pos + 2000:
        print("  Warning: " + slug + " hi section not found")
        continue
    hi_brace = sd.find('{', hi_start)
    depth = 0
    hi_end = hi_brace
    for i in range(hi_brace, len(sd)):
        if sd[i] == '{':
            depth += 1
        elif sd[i] == '}':
            depth -= 1
            if depth == 0:
                hi_end = i + 1
                break
    hi_block_str = sd[hi_brace:hi_end]
    try:
        current_hi = ast.literal_eval(hi_block_str)
    except Exception as ex:
        print("  Warning: " + slug + " parse error: " + str(ex))
        continue
    for key in new_data:
        current_hi[key] = new_data[key]
    new_hi_str = "{\n"
    for k, v in current_hi.items():
        new_hi_str += '   "' + k + '": ' + repr(v) + ',\n'
    new_hi_str += "  }"
    sd = sd[:hi_brace] + new_hi_str + sd[hi_end:]
    count += 1
    faq_count = len(new_data.get("faqs", []))
    print("  Done: " + slug + " (" + str(faq_count) + " FAQs)")

write("schemes_data.py", sd)
print("\nExpanded " + str(count) + " scheme(s)")

print("\nRebuilding site ...")
os.chdir(REPO)
result = os.system(sys.executable + " generate.py")
if result == 0:
    print("Site rebuilt successfully!")
else:
    print("Error - check above")
    sys.exit(1)

print("\nDONE! Now run:")
print("  git add -A")
print('  git commit -m "SEO: expand scheme content"')
print("  git push origin main")
